        state.evaRuntime.ownedEffects = [...new Set(ownedItems.filter((item) => item.type === "effect").map((item) => item.id))];
        state.evaRuntime.ownedDecorations = [...new Set(ownedItems.filter((item) => item.type === "decoration").map((item) => item.id))];
