            return;
        const action = target.dataset.action;
        lastEvaDirectActionAt = Date.now();
        event.preventDefault();
        recordEvaPlayerActivity(action);
        if (action === "eva-click")
            handleEvaRoomSpriteClick();
        if (action === "eva-autonomy-next")
            nextEvaAutonomyLine();
