    function playActionSound(action, target) {
        if (!action || target?.disabled)
            return;
        if (isStudyCardAction(action, target))
            return;
        if (["eva-room-choice", "eva-bg-buy", "eva-bg-select"].includes(action))
            return;
        if (action === "eva-room-shop-open") {
            playUxSound("menu_open");
            return;
        }
        if (action === "eva-room-shop-close") {
            playUxSound("menu_close");
            return;
        }
        if (action === "route") {
            if (target?.closest(".bottom-nav") && hasNavMenu(target.dataset.route)) {
                playUxSound(state.navMenu === target.dataset.route ? "menu_close" : "menu_open");
                return;
            }
            playUxSound("tab_switch");
            return;
        }
        if (action === "nav-menu-route") {
            playUxSound("tab_switch");
            return;
        }
        if (action === "close-nav-menu") {
            playUxSound("menu_close");
            return;
        }
        if (action === "toggle-header-socials") {
            playUxSound(isHeaderSocialOpen() ? "menu_close" : "menu_open");
            return;
        }
        if (action === "show-answer" || action === "open-card") {
            playUxSound("card_flip");
            return;
        }
        if (["close-reward", "close-detail", "pwa-later", "notification-later", "dismiss-mascot-speech"].includes(action)) {
            playUxSound("menu_close");
            return;
        }
        if (action === "notification-center") {
            playUxSound("notification_soft");
            return;
        }
        if (["start-lesson", "select-lesson", "next-sentence", "study-card", "rate", "open-jlpt-lesson", "n5-open-lesson", "n5-overview", "n5-review", "n4-open-lesson", "n4-overview", "n4-review", "n4-kanji", "n4-grammar", "n4-reading", "n4-listening", "n4-final", "n3-open-lesson", "n3-overview", "n3-review", "n3-kanji", "n3-grammar", "n3-reading", "n3-listening", "n3-final", "n2-open-lesson", "n2-overview", "n2-review", "n2-kanji", "n2-grammar", "n2-reading", "n2-listening", "n2-final"].includes(action)) {
            playUxSound("page_turn");
            return;
        }
        if (["n5-answer", "n5-check-input", "n5-srs", "n5-writing-done", "n5-complete-lesson", "n5-final-answer", "n5-final-submit", "n4-answer", "n4-check-input", "n4-srs", "n4-writing-done", "n4-complete-lesson", "n4-grammar-complete", "n4-reading-complete", "n4-listening-complete", "n4-final-answer", "n4-final-submit", "n3-answer", "n3-check-input", "n3-srs", "n3-writing-done", "n3-complete-lesson", "n3-grammar-complete", "n3-reading-complete", "n3-listening-complete", "n3-final-answer", "n3-final-submit", "n2-answer", "n2-check-input", "n2-srs", "n2-writing-done", "n2-complete-lesson", "n2-grammar-complete", "n2-reading-complete", "n2-listening-complete", "n2-final-answer", "n2-final-submit", "n1-answer", "n1-check-input", "n1-srs", "n1-writing-done", "n1-complete-lesson", "n1-grammar-complete", "n1-reading-complete", "n1-listening-complete", "n1-final-answer", "n1-final-submit", "jlpt-lesson-answer"].includes(action)) {
            playUxSound("button_click");
            return;
        }
        if (["pwa-install", "notification-allow", "notification-center", "set-goal"].includes(action)) {
            playUxSound("notification_soft");
            return;
        }
        if (target?.matches("button, .btn, [role='button']"))
            playUxSound("button_click");
        if (action !== "toggle-header-socials")
            setHeaderSocialOpen(false);
    }
    function isStudyCardAction(action, target) {
        if (!["learn", "review"].includes(state.route))
            return false;
        const quietActions = new Set([
            "show-answer",
            "rate",
            "check-reading",
            "play-kanji-audio",
            "start-lesson",
            "select-lesson",
            "study-card"
        ]);
        return quietActions.has(action) || Boolean(target?.closest(".study-card, .study-layout"));
    }
    function handleInput(event) {
        recordEvaPlayerActivity("input");
        const uxVolumeInput = event.target.closest("[data-ux-volume]");
        if (uxVolumeInput) {
            setUxSoundVolume(Number(uxVolumeInput.value) / 100);
            const label = document.querySelector("[data-ux-volume-label]");
            if (label)
                label.textContent = `${Math.round(getUxSoundVolume() * 100)}%`;
            return;
        }
        const readingInput = event.target.closest("[data-reading-input]");
        if (readingInput) {
            state.readingCheck = {
                cardId: readingInput.dataset.id || state.activeCardId,
                value: readingInput.value,
                status: null,
                message: ""
            };
            return;
        }
        const sentenceDraftInput = event.target.closest("[data-sentence-draft]");
        if (sentenceDraftInput) {
            const practice = sentencePracticeProgress();
            const field = sentenceDraftInput.dataset.sentenceDraft;
            practice.customDraft = normalizeCustomSentenceDraft(practice.customDraft || {});
            if (field && Object.prototype.hasOwnProperty.call(practice.customDraft, field)) {
                practice.customDraft[field] = sentenceDraftInput.value;
                practice.customMessage = "";
                practice.customStatus = "";
                saveProgress();
            }
            return;
        }
        const input = event.target.closest("[data-filter]");
        if (!input)
            return;
        const key = input.dataset.filter;
        const selectionStart = input.selectionStart;
        state.filters[key] = input.value;
        state.dictionaryVisibleCount = DICTIONARY_INITIAL_LIMIT;
        render();
        requestAnimationFrame(() => {
            const restored = document.getElementById(input.id);
            if (!restored)
                return;
            restored.focus();
            if (typeof selectionStart === "number" && "setSelectionRange" in restored) {
                restored.setSelectionRange(selectionStart, selectionStart);
            }
        });
    }
    function handleKeydown(event) {
        if (handleFlashKanjiOnboardingKeydown(event))
            return;
        if (handleMoonCheatKey(event))
            return;
        if (event.key === "Escape" && (state.detailCardId || state.rewardModal || state.finalTestModal || state.contactModal || state.navMenu)) {
            state.detailCardId = null;
            state.rewardModal = null;
            state.finalTestModal = null;
            state.contactModal = false;
            state.navMenu = null;
            render();
            return;
        }
        const readingInput = event.target.closest?.("[data-reading-input]");
        if (!readingInput || event.key !== "Enter")
            return;
        event.preventDefault();
        state.readingCheck.value = readingInput.value;
        state.readingCheck.cardId = readingInput.dataset.id || state.activeCardId;
        checkActiveCardReading();
    }
    function handleMoonCheatKey(event) {
        const target = event.target;
        if (target?.closest?.("input, textarea, select, [contenteditable='true']"))
            return false;
        if (event.ctrlKey || event.metaKey || event.altKey || event.key.length !== 1)
            return false;
        moonCheatBuffer = `${moonCheatBuffer}${event.key.toLowerCase()}`.slice(-MOON_CHEAT_CODE.length);
        if (moonCheatBuffer !== MOON_CHEAT_CODE)
            return false;
        moonCheatBuffer = "";
        grantMoonCheat(5000);
        return true;
    }
    function grantMoonCheat(amount = 5000) {
        const value = Math.max(1, Math.min(999999, Math.floor(Number(amount) || 5000)));
        if (!state.progress)
            return 0;
        addReward(0, value, "cheat:moon_farm");
        evaluateAchievements();
        saveProgress();
        playUxSound("moon_fragment_gain");
        toast(lang() === "ru" ? `\u0427\u0438\u0442 \u0430\u043A\u0442\u0438\u0432\u0438\u0440\u043E\u0432\u0430\u043D: +${value} Moon` : `Cheat activated: +${value} Moon`);
        render();
        return state.progress.moonFragments;
    }
