            return "mystic";
        if (context.shopOpen || eventType === "shop_opened" || eventType === "item_bought")
            return "curious";
        if (context.route === "learn" || context.route === "review" || context.dueReviews > 0)
            return "focused";
        if (context.mistakesToday >= 4)
            return context.correctToday > context.mistakesToday ? "soft" : "strict";
